import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const META_API_VERSION = "v24.0";
const META_API_BASE = `https://graph.facebook.com/${META_API_VERSION}`;

const corsHeaders = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

interface CreateCampaignRequest {
    integration_id: string;
    campaign: {
        name: string;
        objective: string;
        status: string;
        special_ad_categories?: string[];
    };
    adset: {
        name: string;
        daily_budget?: number; // em centavos
        lifetime_budget?: number; // em centavos
        start_time: string;
        end_time?: string;
        billing_event: string;
        optimization_goal: string;
        targeting: any;
    };
    ad: {
        name: string;
        creative: {
            title: string;
            body: string;
            image_url?: string;
            image_hash?: string;
            link_url: string;
            call_to_action: string;
            page_id: string;
            instagram_actor_id?: string;
        };
    };
}

Deno.serve(async (req) => {
    if (req.method === 'OPTIONS') {
        return new Response('ok', { headers: corsHeaders });
    }


    try {
        const supabaseUrl = Deno.env.get('SUPABASE_URL')!;
        const supabaseServiceKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!;
        const supabase = createClient(supabaseUrl, supabaseServiceKey);

        const authHeader = req.headers.get('Authorization');
        if (!authHeader) throw new Error('Missing authorization header');

        const { data: { user }, error: authError } = await supabase.auth.getUser(
            authHeader.replace('Bearer ', '')
        );
        if (authError || !user) throw new Error('Unauthorized');

        const { data: userData, error: userError } = await supabase
            .from('users')
            .select('company_id')
            .eq('id', user.id)
            .single();

        if (userError || !userData?.company_id) throw new Error('User company not found');

        const payload = await req.json() as CreateCampaignRequest;
        const { integration_id, campaign, adset, ad } = payload;

        // 1. Get Integration Token
        const { data: integration, error: intError } = await supabase
            .from('integrations')
            .select('*')
            .eq('id', integration_id)
            .eq('company_id', userData.company_id)
            .single();

        if (intError || !integration) throw new Error('Integration not found');
        const accessToken = integration.access_token;
        const accountId = integration.account_id;

        // Helper for Meta API calls
        const metaRequest = async (endpoint: string, method: string, body: any) => {
            const url = `${META_API_BASE}/${endpoint}`;
            const response = await fetch(url, {
                method,
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ ...body, access_token: accessToken })
            });
            const data = await response.json();
            if (!response.ok) {
                console.error(`Meta API Error (${endpoint}):`, data);
                throw new Error(data.error?.message || 'Meta API request failed');
            }
            return data;
        };

        // 2. Create Campaign
        console.log('Creating campaign...');
        const campaignData = await metaRequest(`act_${accountId}/campaigns`, 'POST', {
            name: campaign.name,
            objective: campaign.objective,
            status: campaign.status,
            special_ad_categories: campaign.special_ad_categories ? [campaign.special_ad_categories] : ['NONE'],
        });
        const campaignId = campaignData.id;

        try {
            // 3. Create Ad Set
            console.log(`Creating ad set for campaign ${campaignId}...`);
            const adSetData = await metaRequest(`act_${accountId}/adsets`, 'POST', {
                name: adset.name,
                campaign_id: campaignId,
                daily_budget: adset.daily_budget, // Meta expects cents as string/number
                lifetime_budget: adset.lifetime_budget,
                start_time: adset.start_time,
                billing_event: adset.billing_event,
                optimization_goal: adset.optimization_goal,
                targeting: adset.targeting,
                status: campaign.status,
                bid_strategy: 'LOWEST_COST_WITHOUT_CAP', // Simplified for V1
            });
            const adSetId = adSetData.id;

            // 4. Create Ad Creative
            console.log(`Creating ad creative...`);

            // Simplified Image Hash Logic: If URL provided, fetch and hash? Or assume frontend sends hash?
            // For V1, we assume URL is public or hash is provided. Meta supports image_url in object_story_spec for link ads.
            const creativePayload = {
                name: `${ad.name} - Creative`,
                object_story_spec: {
                    page_id: ad.creative.page_id,
                    instagram_actor_id: ad.creative.instagram_actor_id, // Optional
                    link_data: {
                        call_to_action: {
                            type: ad.creative.call_to_action,
                            value: { link: ad.creative.link_url }
                        },
                        link: ad.creative.link_url,
                        message: ad.creative.body, // Text
                        name: ad.creative.title, // Headline
                        picture: ad.creative.image_url, // For link ads
                        image_hash: ad.creative.image_hash
                    }
                }
            };

            const creativeData = await metaRequest(`act_${accountId}/adcreatives`, 'POST', creativePayload);
            const creativeId = creativeData.id;

            // 5. Create Ad
            console.log(`Creating ad...`);
            const adData = await metaRequest(`act_${accountId}/ads`, 'POST', {
                name: ad.name,
                adset_id: adSetId,
                creative: { creative_id: creativeId },
                status: campaign.status
            });
            const adId = adData.id;

            // 6. Log success to DB
            await supabase.from('sync_history').insert({
                company_id: userData.company_id,
                integration_id: integration.id,
                sync_type: 'campaign_created',
                status: 'completed',
                records_synced: 1,
                details: { campaignId, adSetId, adId }
            });

            return new Response(JSON.stringify({
                success: true,
                campaign_id: campaignId,
                adset_id: adSetId,
                ad_id: adId
            }), {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 200
            });

        } catch (error) {
            console.error('Error in creation chain, attempting rollback (deleting campaign)...', error);
            // Rollback: Delete the campaign (which cascades deletes adset/ads)
            try {
                await metaRequest(campaignId, 'DELETE', {});
                console.log('Rollback successful: Campaign deleted.');
            } catch (delError) {
                console.error('Failed to rollback campaign:', delError);
            }
            throw error; // Re-throw to be caught by main catch
        }

    } catch (error) {
        console.error('Create campaign error:', error);
        return new Response(JSON.stringify({ error: String(error) }), {
            headers: { ...corsHeaders, 'Content-Type': 'application/json' },
            status: 400
        });
    }
});

import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const META_API_VERSION = "v24.0";
const META_API_BASE = `https://graph.facebook.com/${META_API_VERSION}`;

const corsHeaders = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

Deno.serve(async (req) => {
    if (req.method === 'OPTIONS') {
        return new Response('ok', { headers: corsHeaders });
    }


    try {
        const supabaseUrl = Deno.env.get('SUPABASE_URL')!;
        const supabaseServiceKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!;
        const supabase = createClient(supabaseUrl, supabaseServiceKey);

        const authHeader = req.headers.get('Authorization');
        if (!authHeader) throw new Error('Missing authorization header');

        const { data: { user }, error: authError } = await supabase.auth.getUser(
            authHeader.replace('Bearer ', '')
        );
        if (authError || !user) throw new Error('Unauthorized');

        const { integration_id } = await req.json();
        if (!integration_id) throw new Error('Missing integration_id');

        const { data: integration, error: intError } = await supabase
            .from('integrations')
            .select('access_token')
            .eq('id', integration_id)
            .single();

        if (intError || !integration) throw new Error('Integration not found');

        // Fetch Pages
        // access_token should be a User Access Token with 'pages_show_list' permission
        const url = `${META_API_BASE}/me/accounts?fields=id,name,access_token,picture&access_token=${integration.access_token}`;

        const response = await fetch(url);
        const data = await response.json();

        if (!response.ok) {
            console.error('Meta API Error (Pages):', data);
            throw new Error(data.error?.message || 'Failed to list pages');
        }

        return new Response(JSON.stringify({ pages: data.data || [] }), {
            headers: { ...corsHeaders, 'Content-Type': 'application/json' },
            status: 200
        });

    } catch (error) {
        console.error('List pages error:', error);
        return new Response(JSON.stringify({ error: String(error) }), {
            headers: { ...corsHeaders, 'Content-Type': 'application/json' },
            status: 400
        });
    }
});

import "jsr:@supabase/functions-js/edge-runtime.d.ts";
import { createClient } from "jsr:@supabase/supabase-js@2";

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
};

interface MetaTokenResponse {
  access_token: string;
  token_type: string;
  expires_in: number;
}

interface MetaAdAccount {
  id: string;
  name: string;
  account_id: string;
  account_status: number;
  currency: string;
  timezone_name: string;
}

Deno.serve(async (req: Request) => {
  // Handle CORS preflight
  if (req.method === "OPTIONS") {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    const url = new URL(req.url);
    const code = url.searchParams.get("code");
    const state = url.searchParams.get("state");
    const error = url.searchParams.get("error");
    const errorDescription = url.searchParams.get("error_description");

    // Handle OAuth errors
    if (error) {
      console.error("OAuth error:", error, errorDescription);
      return new Response(
        JSON.stringify({ error, error_description: errorDescription }),
        { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    // Validate required params
    if (!code || !state) {
      return new Response(
        JSON.stringify({ error: "Missing code or state parameter" }),
        { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    // Parse state (contains user_id and company_id)
    let stateData: { user_id: string; company_id: string; redirect_url: string };
    try {
      stateData = JSON.parse(atob(state));
    } catch {
      return new Response(
        JSON.stringify({ error: "Invalid state parameter" }),
        { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    // Get Meta App credentials from environment
    const META_APP_ID = Deno.env.get("META_APP_ID");
    const META_APP_SECRET = Deno.env.get("META_APP_SECRET");
    const SUPABASE_URL = Deno.env.get("SUPABASE_URL");
    const SUPABASE_SERVICE_ROLE_KEY = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");

    if (!META_APP_ID || !META_APP_SECRET) {
      console.error("Meta App credentials not configured");
      return new Response(
        JSON.stringify({ error: "Meta App not configured" }),
        { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    // Exchange code for access token
    const redirectUri = `${SUPABASE_URL}/functions/v1/meta-oauth-callback`;
    const tokenUrl = `https://graph.facebook.com/v24.0/oauth/access_token?client_id=${META_APP_ID}&redirect_uri=${encodeURIComponent(redirectUri)}&client_secret=${META_APP_SECRET}&code=${code}`;

    const tokenResponse = await fetch(tokenUrl);
    const tokenData: MetaTokenResponse = await tokenResponse.json();

    if (!tokenResponse.ok || !tokenData.access_token) {
      console.error("Failed to exchange code for token:", tokenData);
      return new Response(
        JSON.stringify({ error: "Failed to get access token" }),
        { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    // Exchange short-lived token for long-lived token
    const longLivedUrl = `https://graph.facebook.com/v24.0/oauth/access_token?grant_type=fb_exchange_token&client_id=${META_APP_ID}&client_secret=${META_APP_SECRET}&fb_exchange_token=${tokenData.access_token}`;

    const longLivedResponse = await fetch(longLivedUrl);
    const longLivedData: MetaTokenResponse = await longLivedResponse.json();

    const accessToken = longLivedData.access_token || tokenData.access_token;
    const expiresIn = longLivedData.expires_in || tokenData.expires_in;

    // Fetch ad accounts
    const adAccountsUrl = `https://graph.facebook.com/v24.0/me/adaccounts?fields=id,name,account_id,account_status,currency,timezone_name&access_token=${accessToken}`;
    const adAccountsResponse = await fetch(adAccountsUrl);
    const adAccountsData = await adAccountsResponse.json();

    if (!adAccountsResponse.ok) {
      console.error("Failed to fetch ad accounts:", adAccountsData);
      return new Response(
        JSON.stringify({ error: "Failed to fetch ad accounts" }),
        { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    const adAccounts: MetaAdAccount[] = adAccountsData.data || [];

    // Initialize Supabase client
    const supabase = createClient(
      SUPABASE_URL!,
      SUPABASE_SERVICE_ROLE_KEY!
    );

    // Calculate token expiration
    const tokenExpiresAt = new Date(Date.now() + expiresIn * 1000).toISOString();

    // Save each ad account as an integration
    const integrations = [];
    for (const account of adAccounts) {
      const { data: integration, error: insertError } = await supabase
        .from("integrations")
        .upsert({
          company_id: stateData.company_id,
          user_id: stateData.user_id,
          platform: "meta",
          account_id: account.account_id,
          account_name: account.name,
          access_token: accessToken,
          token_expires_at: tokenExpiresAt,
          status: account.account_status === 1 ? "active" : "inactive",
          permissions: {
            currency: account.currency,
            timezone: account.timezone_name,
            account_status: account.account_status
          }
        }, {
          onConflict: "company_id,account_id",
          ignoreDuplicates: false
        })
        .select()
        .single();

      if (insertError) {
        console.error("Error saving integration:", insertError);
      } else {
        integrations.push(integration);
      }
    }

    // Save OAuth session
    const sessionId = crypto.randomUUID();
    await supabase.from("oauth_sessions").insert({
      id: sessionId,
      user_id: stateData.user_id,
      access_token: accessToken,
      accounts: adAccounts.map(a => ({ id: a.account_id, name: a.name })),
      expires_at: tokenExpiresAt
    });

    // Redirect back to the app
    const redirectUrl = new URL(stateData.redirect_url || "/integracoes");
    redirectUrl.searchParams.set("success", "true");
    redirectUrl.searchParams.set("accounts", adAccounts.length.toString());

    return new Response(null, {
      status: 302,
      headers: {
        ...corsHeaders,
        Location: redirectUrl.toString()
      }
    });

  } catch (error) {
    console.error("Unexpected error:", error);
    return new Response(
      JSON.stringify({ error: "Internal server error" }),
      { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  }
});
